import java.util.*;
import java.lang.*;
import java.io.*;

class LimitExceededException extends Exception {
    public LimitExceededException(String message) {
        super(message);
    }
}

class LibraryUser {
    String name;
    int borrowedBooks;

    public LibraryUser(String name) {
        this.name = name;
        this.borrowedBooks = 0;
    }

    public void borrowBook() throws LimitExceededException {
        if (borrowedBooks >= 3) {
            throw new LimitExceededException("Cannot borrow more than 3 books");
        }
        borrowedBooks++;
        System.out.println("Book borrowed");
    }
}

class Codechef {
    public static void main(String[] args) throws java.lang.Exception {
        Scanner sc = new Scanner(System.in);

        String name = sc.nextLine();
        int n = sc.nextInt();

        LibraryUser user = new LibraryUser(name);

        for (int i = 0; i < n; i++) {
            try {
                user.borrowBook();
            } catch (LimitExceededException e) {
                System.out.println("LimitExceededException: " + e.getMessage());
            }
        }

        sc.close();
    }
}
